  unsigned int localThreads[2] = {blockSize, blockSize};

  if((unsigned int)(localThreads[0] * localThreads[0]) > 256)
  {
    blockSize = 16;
    localThreads[0] = blockSize;
    localThreads[1] = blockSize;
  }

  int numTeams = (int)((globalThreads[0] / localThreads[0]) * (globalThreads[1] / localThreads[1]));
  int threadLimit = (int)(localThreads[0] * localThreads[1]);

  int deviceId = omp_get_default_device();
  int hostId = omp_get_initial_device();

