      for(int yValue = 0; yValue < (int)numNodes; yValue++)
      {
        for(int xValue = 0; xValue < (int)numNodes; xValue++)
        {
          int k = (int)pass;
          unsigned int oldWeight = pathDistanceBuffer[(size_t)yValue * numNodes + xValue];
          unsigned int tempWeight = pathDistanceBuffer[(size_t)yValue * numNodes + k] +
                                    pathDistanceBuffer[(size_t)k * numNodes + xValue];

          if (tempWeight < oldWeight)
          {
            pathDistanceBuffer[(size_t)yValue * numNodes + xValue] = tempWeight;
