  int Lx = atoi(argv[1]);
  int Ly = atoi(argv[2]);
  if (Lx % NTX != 0 || Ly % NTY != 0) {
    printf("Array length LX and LY must be a multiple of block size %d and %d, respectively\n",
           NTX, NTY);
    exit(1);
  }

  int niter = atoi(argv[3]);
  assert(niter >= 1);

  const float sigma = 0.01f;
  const float xdelta = sigma / (1.0f + 4.0f*sigma);
  const float xnorm = 1.0f / (1.0f + 4.0f*sigma);

  printf(" Ly,Lx = %d,%d\n", Ly, Lx);
  printf(" niter = %d\n", niter);

  srand(123);
  size_t N = (size_t)Lx * (size_t)Ly;
  size_t bytes = sizeof(float) * N;

  float *buffer = (float*) malloc(bytes);
  float *h_out = (float*) malloc(bytes);
  float *h_in  = (float*) malloc(bytes);
  float *d_res = (float*) malloc(bytes);

  int i, j, x, y;
  for (i = 0; i < Lx; i += 16) {
    x = rand() % Lx;
    for (j = 0; j < Ly; j++)
      buffer[x + j*Lx] = 1.f;
  }
  for (i = 0; i < Ly; i += 16) {
    y = rand() % Ly;
    for (j = 0; j < Lx; j++)
      buffer[j + y*Lx] = 1.f;
  }
  memcpy(h_in, buffer, bytes);

  for (i = 0; i < niter; i++) {
    reference(h_out, h_in, xdelta, xnorm, Lx, Ly);
    std::swap(h_out, h_in);
  }

  int dev = omp_get_default_device();
  int host = omp_get_initial_device();

  float *d_in = (float*) omp_target_alloc(bytes, dev);
  float *d_out = (float*) omp_target_alloc(bytes, dev);

  omp_target_memcpy(d_in, buffer, bytes, 0, 0, dev, host);

  double t0 = stop_watch(0);

  int num_teams = (Lx / NTX) * (Ly / NTY);
  for (i = 0; i < niter; i++) {
    #pragma omp target teams distribute parallel for device(dev) is_device_ptr(d_out, d_in) thread_limit(NTX*NTY) num_teams(num_teams)
    for (int idx = 0; idx < (int)N; idx++) {
      int xx = idx % Lx;
      int yy = idx / Lx;
      int v00 = yy*Lx + xx;
      int v0p = yy*Lx + (xx + 1)%Lx;
      int v0m = yy*Lx + (Lx + xx - 1)%Lx;
      int vp0 = ((yy + 1)%Ly)*Lx + xx;
      int vm0 = ((Ly + yy - 1)%Ly)*Lx + xx;
      d_out[v00] = xnorm*d_in[v00] + xdelta*(d_in[v0p] + d_in[v0m] + d_in[vp0] + d_in[vm0]);
    }
    std::swap(d_out, d_in);
  }

  t0 = stop_watch(t0) / (double)niter;

  printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
         niter, Lx, Ly, t0,
         Lx*Ly*sizeof(float)*2.0/(t0*1.0e3),
         (Lx*Ly*6.0)/(t0*1.0e3));

  omp_target_memcpy(d_res, d_in, bytes, 0, 0, host, dev);

  bool ok = true;
  for (i = 0; i < (int)N; i++) {
    if (fabs(h_in[i] - d_res[i]) > 1e-2) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, h_in[i], d_res[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  omp_target_free(d_in, dev);
  omp_target_free(d_out, dev);
  free(buffer);
  free(h_out);
  free(h_in);
  free(d_res);
  return 0;
}

