  for(int i = 0; i < initialDepth; ++i)
    root_prefixes[num_sol].board[i] = board[i];
}

inline bool MCstillLegal(const int8_t *board, const int r)
{
  for (int i = 0; i < r; ++i)
    if (board[i] == board[r]) return false;

  int ld = board[r];
  int rd = board[r];
  for (int i = r - 1; i >= 0; --i) {
    --ld; ++rd;
    if (board[i] == ld || board[i] == rd) return false;
  }
  return true;
}

