      exit(1);
    }

    omp_target_memcpy(root_prefixes_d, root_prefixes_h, prefixes_bytes, 0, 0, dev, host);
  }

  printf("\n### Regular BP-DFS search. ###\n");

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    if (n_explorers > 0) {
      BP_queens_root_dfs(
        size,
        n_explorers,
        initial_depth,
        root_prefixes_d,
        vector_of_tree_size_d,
        sols_d);
    }
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

  if (n_explorers > 0) {
    omp_target_memcpy(vector_of_tree_size_h, vector_of_tree_size_d, ull_bytes, 0, 0, host, dev);
    omp_target_memcpy(sols_h, sols_d, ull_bytes, 0, 0, host, dev);

    omp_target_free(vector_of_tree_size_d, dev);
    omp_target_free(sols_d, dev);
    omp_target_free(root_prefixes_d, dev);
  }
}

