#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T>
void conv1d_kernel(const T * __restrict__ in,
                         T * __restrict__ out,
                   const T * __restrict__ mask,
                   const int input_width,
                   const int mask_width,
                   const int bs)
{
  const int grids = input_width / bs;
  #pragma omp target teams distribute parallel for is_device_ptr(in, out, mask) num_teams(grids) thread_limit(bs)
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += in[start + j] * mask[j];
      }
    }
    out[i] = s;
  }
}

template<typename T>
void conv1d_tiled_kernel(const T * __restrict__ in,
                               T * __restrict__ out,
                         const T * __restrict__ mask,
                         const int input_width,
                         const int mask_width,
                         const int bs)
{
  const int grids = input_width / bs;
  #pragma omp target teams is_device_ptr(in, out, mask) num_teams(grids) thread_limit(bs)
  {
    T tile[MAX_BLOCK_SIZE + MAX_MASK_WIDTH - 1];
    const int block = omp_get_team_num();
    const int n = mask_width / 2;

    #pragma omp parallel num_threads(bs)
    {
      const int tid = omp_get_thread_num();
      const int i = tid + block * bs;

      int halo_left = (block - 1) * bs + tid;
      if (tid >= bs - n) {
        tile[tid - (bs - n)] = halo_left < 0 ? (T)0 : in[halo_left];
      }

      tile[n + tid] = in[block * bs + tid];

      int halo_right = (block + 1) * bs + tid;
      if (tid < n) {
        tile[tid + bs + n] = halo_right >= input_width ? (T)0 : in[halo_right];
      }

      #pragma omp barrier

      T s = 0;
      for (int j = 0; j < mask_width; j++) {
        s += tile[tid + j] * mask[j];
      }

      out[i] = s;
    }
  }
}

template<typename T>
void conv1d_tiled_caching_kernel(const T * __restrict__ in,
                                       T * __restrict__ out,
                                 const T * __restrict__ mask,
                                 const int input_width,
                                 const int mask_width,
                                 const int bs)
{
  const int grids = input_width / bs;
  #pragma omp target teams is_device_ptr(in, out, mask) num_teams(grids) thread_limit(bs)
  {
    T tile[MAX_BLOCK_SIZE];
    const int block = omp_get_team_num();
    const int this_tile_start = block * bs;
    const int next_tile_start = (block + 1) * bs;

    #pragma omp parallel num_threads(bs)
    {
      const int tid = omp_get_thread_num();
      const int i = tid + block * bs;

      tile[tid] = in[i];

      #pragma omp barrier

      int start = i - (mask_width / 2);
      T s = 0;
      for (int j = 0; j < mask_width; j++) {
        int in_index = start + j;
        if (in_index >= 0 && in_index < input_width) {
          if (in_index >= this_tile_start && in_index < next_tile_start) {
            s += tile[tid + j - (mask_width / 2)] * mask[j];
          } else {
            s += in[in_index] * mask[j];
          }
        }
      }
      out[i] = s;
    }
  }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
